import base64

# Replace this with your actual Base64-encoded audio string
base64_audio_string = ""

# Decode the Base64 string
try:
    audio_data = base64.b64decode(base64_audio_string)
    
    # Save the decoded audio to a file
    output_file = "output_audio.mp3"  # Change extension based on your audio format (e.g., .wav, .mp3)
    with open(output_file, "wb") as audio_file:
        audio_file.write(audio_data)
    
    print(f"Audio file saved as {output_file}")
except Exception as e:
    print(f"Error decoding Base64 audio: {e}")